const tableName = "Mystery Event Focus Table";

const table = game.tables.getName(tableName);

if (!table) {
  ui.notifications.error(`RollTable "${tableName}" not found.`);
  return;
}

// Roll d100
const roll = await new Roll("1d100").evaluate();

// Draw from table using roll
const draw = await table.draw({
  roll: roll,
  displayChat: false
});

const result = draw.results[0];

// Output to chat
let content = `
<h2>🎲 Mystery Event Focus</h2>

<p>
<strong>Roll:</strong> ${roll.total}
</p>

<p>
<strong>Result [${roll.total}]:</strong> ${result.text}
</p>
`;

ChatMessage.create({
  user: game.user.id,
  speaker: ChatMessage.getSpeaker(),
                   content: content
});
